func (m *MockBookmarkService) GetMostRecents(userID uuid.UUID) ([]repository.Bookmark, error) {
	m.mutex.Lock()
	m.GetMostRecentsCallCount++
	m.LastGetMostRecentsUserID = userID
	m.mutex.Unlock()
	
	if m.ShouldFailGetMostRecents {
		return nil, errors.New(m.GetMostRecentsErrorMessage)
	}
	
	m.mutex.RLock()
	defer m.mutex.RUnlock()
	
	userBookmarks := make([]repository.Bookmark, 0)
	if bookmarks, exists := m.bookmarksByUser[userID]; exists {
		// Sort by updated datetime descending (most recent first)
		sortedBookmarks := make([]*repository.Bookmark, len(bookmarks))
		copy(sortedBookmarks, bookmarks)
		
		// Simple bubble sort by UpdatedDatetime descending
		for i := 0; i < len(sortedBookmarks); i++ {
			for j := 0; j < len(sortedBookmarks)-1-i; j++ {
				if sortedBookmarks[j].UpdatedDatetime != nil && sortedBookmarks[j+1].UpdatedDatetime != nil {
					if sortedBookmarks[j].UpdatedDatetime.Before(*sortedBookmarks[j+1].UpdatedDatetime) {
						sortedBookmarks[j], sortedBookmarks[j+1] = sortedBookmarks[j+1], sortedBookmarks[j]
					}
				}
			}
		}
		
		for _, bookmark := range sortedBookmarks {
			userBookmarks = append(userBookmarks, *bookmark)
		}
	}
	
	return userBookmarks, nil
}

