func (m *MockBookmarkService) Create(params *repository.CreateBookmarkParams) (*repository.Bookmark, error) {
	m.mutex.Lock()
	m.CreateCallCount++
	m.LastCreateParams = params
	m.mutex.Unlock()
	
	if m.ShouldFailCreate {
		return nil, errors.New(m.CreateErrorMessage)
	}
	
	if params == nil {
		return nil, errors.New("create parameters cannot be nil")
	}
	
	// Basic validation
	if params.Name == "" {
		return nil, errors.New("bookmark name cannot be empty")
	}
	if params.Link == "" {
		return nil, errors.New("bookmark link cannot be empty")
	}
	
	m.mutex.Lock()
	defer m.mutex.Unlock()
	
	// Check for duplicate name within same folder
	if bookmarks, exists := m.bookmarksByFolder[params.FolderID]; exists {
		for _, bookmark := range bookmarks {
			if bookmark.Name == params.Name {
				return nil, errors.New("bookmark name already exists in this folder")
			}
		}
	}
	
	now := time.Now()
	newBookmark := &repository.Bookmark{
		ID:       uuid.New(),
		UserID:   params.UserID,
		FolderID: params.FolderID,
		Name:     params.Name,
		Link:     params.Link,
		Icon:     nil, // Will be set by application layer
		Description: nil,
		CreatedDatetime: &now,
		UpdatedDatetime: &now,
	}
	
	// Store bookmark
	m.bookmarks[newBookmark.ID] = newBookmark
	
	// Update indexes
	if userBookmarks, exists := m.bookmarksByUser[params.UserID]; exists {
		m.bookmarksByUser[params.UserID] = append(userBookmarks, newBookmark)
	} else {
		m.bookmarksByUser[params.UserID] = []*repository.Bookmark{newBookmark}
	}
	
	if folderBookmarks, exists := m.bookmarksByFolder[params.FolderID]; exists {
		m.bookmarksByFolder[params.FolderID] = append(folderBookmarks, newBookmark)
	} else {
		m.bookmarksByFolder[params.FolderID] = []*repository.Bookmark{newBookmark}
	}
	
	return newBookmark, nil
}

func (m *MockBookmarkService) Update(id uuid.UUID, params *repository.UpdateBookmarkParams) (*repository.Bookmark, error) {
	m.mutex.Lock()
	m.UpdateCallCount++
	m.LastUpdateID = id
	m.LastUpdateParams = params
	m.mutex.Unlock()
	
	if m.ShouldFailUpdate {
		return nil, errors.New(m.UpdateErrorMessage)
	}
	
	if params == nil {
		return nil, errors.New("update parameters cannot be nil")
	}
	
	m.mutex.Lock()
	defer m.mutex.Unlock()
	
	bookmark, exists := m.bookmarks[id]
	if !exists {
		return nil, errors.New("bookmark not found")
	}
	
	// Basic validation
	if params.Name == "" {
		return nil, errors.New("bookmark name cannot be empty")
	}
	if params.Link == "" {
		return nil, errors.New("bookmark link cannot be empty")
	}
	
	// If folder is changing, update indexes
	if bookmark.FolderID != params.FolderID {
		// Remove from old folder index
		if folderBookmarks, exists := m.bookmarksByFolder[bookmark.FolderID]; exists {
			for i, b := range folderBookmarks {
				if b.ID == id {
					m.bookmarksByFolder[bookmark.FolderID] = append(folderBookmarks[:i], folderBookmarks[i+1:]...)
					break
				}
			}
		}
		
		// Add to new folder index
		if folderBookmarks, exists := m.bookmarksByFolder[params.FolderID]; exists {
			m.bookmarksByFolder[params.FolderID] = append(folderBookmarks, bookmark)
		} else {
			m.bookmarksByFolder[params.FolderID] = []*repository.Bookmark{bookmark}
		}
	}
	
	// Update bookmark
	now := time.Now()
	bookmark.FolderID = params.FolderID
	bookmark.Name = params.Name
	bookmark.Link = params.Link
	bookmark.UpdatedDatetime = &now
	
	return bookmark, nil
}

