func (m *MockBookmarkService) Remove(id uuid.UUID) error {
	m.mutex.Lock()
	m.RemoveCallCount++
	m.LastRemoveID = id
	m.mutex.Unlock()
	
	if m.ShouldFailRemove {
		return errors.New(m.RemoveErrorMessage)
	}
	
	m.mutex.Lock()
	defer m.mutex.Unlock()
	
	bookmark, exists := m.bookmarks[id]
	if !exists {
		return errors.New("bookmark not found")
	}
	
	// Remove from main storage
	delete(m.bookmarks, id)
	
	// Remove from user index
	if userBookmarks, exists := m.bookmarksByUser[bookmark.UserID]; exists {
		for i, b := range userBookmarks {
			if b.ID == id {
				m.bookmarksByUser[bookmark.UserID] = append(userBookmarks[:i], userBookmarks[i+1:]...)
				break
			}
		}
	}
	
	// Remove from folder index
	if folderBookmarks, exists := m.bookmarksByFolder[bookmark.FolderID]; exists {
		for i, b := range folderBookmarks {
			if b.ID == id {
				m.bookmarksByFolder[bookmark.FolderID] = append(folderBookmarks[:i], folderBookmarks[i+1:]...)
				break
			}
		}
	}
	
	return nil
}